import { useState } from 'react';
import NuevaAsignaturaModal from './NuevaAsignaturaModal';

function Dashboard({ setPantalla }) {
  const [modalOpen, setModalOpen] = useState(false);
  const [asignaturas, setAsignaturas] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleGuardar = (datos) => {
    setLoading(true);
    setTimeout(() => {
      setAsignaturas((prev) => [...prev, { ...datos, id: Date.now() }]);
      setLoading(false);
      setModalOpen(false);
    }, 600);
  };

  return (
    <div style={{ padding: '2rem', backgroundColor: '#0f1117', minHeight: '100vh', color: '#e8eaf0' }}>

      {/* Encabezado */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <h1 style={{ margin: 0, fontSize: '1.5rem' }}>EDU·STRATEGY</h1>
        <button
          onClick={() => setPantalla('login')}
          style={{ background: 'transparent', border: '1px solid #3d4560', color: '#8892a4', padding: '0.4rem 1rem', borderRadius: '6px', cursor: 'pointer' }}
        >
          Cerrar sesión
        </button>
      </div>

      {/* Botón crear asignatura */}
      <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: '1rem' }}>
        <button
          onClick={() => setModalOpen(true)}
          style={{ backgroundColor: '#3b82f6', border: 'none', color: '#fff', padding: '0.6rem 1.25rem', borderRadius: '8px', cursor: 'pointer', fontWeight: '600' }}
        >
          + Crear asignatura
        </button>
      </div>

      {/* Tabla de asignaturas */}
      {asignaturas.length === 0 ? (
        <p style={{ color: '#8892a4', textAlign: 'center', marginTop: '3rem' }}>
          No hay asignaturas registradas. ¡Crea la primera!
        </p>
      ) : (
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ borderBottom: '1px solid #2a3045' }}>
              <th style={{ textAlign: 'left', padding: '0.75rem', color: '#8892a4', fontSize: '0.8rem' }}>ASIGNATURA</th>
              <th style={{ textAlign: 'left', padding: '0.75rem', color: '#8892a4', fontSize: '0.8rem' }}>DOCENTE</th>
              <th style={{ textAlign: 'left', padding: '0.75rem', color: '#8892a4', fontSize: '0.8rem' }}>SEMESTRE</th>
            </tr>
          </thead>
          <tbody>
            {asignaturas.map((a) => (
              <tr key={a.id} style={{ borderBottom: '1px solid #1e2130' }}>
                <td style={{ padding: '0.75rem', color: '#d1d5e0' }}>{a.nombre}</td>
                <td style={{ padding: '0.75rem', color: '#d1d5e0' }}>{a.docente}</td>
                <td style={{ padding: '0.75rem', color: '#d1d5e0' }}>{a.semestre}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {/* Modal */}
      <NuevaAsignaturaModal
        isOpen={modalOpen}
        onClose={() => setModalOpen(false)}
        onGuardar={handleGuardar}
        loading={loading}
      />

    </div>
  );
}

export default Dashboard;
